"use strict";(globalThis.webpackChunkcybersec_kb=globalThis.webpackChunkcybersec_kb||[]).push([[4366],{7835(e){e.exports=JSON.parse('{"tag":{"label":"attack","permalink":"/niebezpiecznik_szkolenie/docs/tags/attack","allTagsPath":"/niebezpiecznik_szkolenie/docs/tags","count":7,"items":[{"id":"theory/git-exposure","title":".git Exposure \u2014 Source Code Leaks","description":"An exposed .git/ directory on a web server lets attackers reconstruct the entire source code of an application \u2014 including secrets and API keys from the full commit history.","permalink":"/niebezpiecznik_szkolenie/docs/theory/git-exposure"},{"id":"theory/cryptographic-failures","title":"Cryptographic Failures","description":"Cryptographic Failures (OWASP A02:2021) covers weak algorithms, poor TLS config, insecure password storage, and secrets leaking in code \u2014 all of which can expose sensitive data.","permalink":"/niebezpiecznik_szkolenie/docs/theory/cryptographic-failures"},{"id":"theory/csrf","title":"CSRF \u2014 Cross-Site Request Forgery","description":"CSRF tricks a logged-in user\'s browser into sending an authenticated request to a target site without their knowledge, because browsers automatically attach cookies to matching requests.","permalink":"/niebezpiecznik_szkolenie/docs/theory/csrf"},{"id":"theory/http-headers","title":"HTTP Headers & CF-Connecting-IP Spoofing","description":"If a server blindly trusts IP headers like CF-Connecting-IP or X-Forwarded-For without verifying the request actually came through Cloudflare, attackers can spoof any IP address.","permalink":"/niebezpiecznik_szkolenie/docs/theory/http-headers"},{"id":"theory/injection-xss","title":"Injection & XSS","description":"Injection attacks insert malicious code into a trusted context; XSS is the browser-side variant where attacker-controlled scripts execute in a victim\'s browser.","permalink":"/niebezpiecznik_szkolenie/docs/theory/injection-xss"},{"id":"theory/iot-zero-day","title":"IoT, Smart Devices & Zero-day","description":"IoT devices expand the attack surface with outdated firmware and default credentials, making zero-day vulnerabilities especially dangerous since these devices are rarely patched.","permalink":"/niebezpiecznik_szkolenie/docs/theory/iot-zero-day"},{"id":"theory/jwt","title":"JWT \u2014 JSON Web Token","description":"JWT is a three-part base64-encoded token used for authentication, but misconfigurations like weak secrets or the alg:none attack can allow attackers to forge tokens.","permalink":"/niebezpiecznik_szkolenie/docs/theory/jwt"}],"unlisted":false}}')}}]);